import React from 'react';
import { StructuredList as CarbonStructuredList } from '@carbon/react';

const StructuredList = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonStructuredList
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonStructuredList>
    );
};

StructuredList.defaultProps = {
    className: ''
};

export default StructuredList;
